def parse_config(filepath: str) -> dict:
    """解析配置文件（有缺陷版本）"""
    result = {}
    with open(filepath, 'r') as f:
        for line in f:
            line = line.strip()
            # 缺陷1: 注释如果包含=会被错误解析
